-- Bite of Seattle lineup import from the user-provided source.
-- Includes 127 Food & Beverage vendors, 3 Games, and the 5 Shopping examples actually present.
-- Idempotent: existing vendors are matched by case-insensitive trimmed name and keep their UUIDs.

begin;
create extension if not exists pgcrypto;
create temporary table lineup_import(name text not null,vendor_type text not null,menu_items text[] not null,sort_order integer not null) on commit drop;
update public.vendors v set vendor_type=s.vendor_type,menu_items=s.menu_items,source='Bite of Seattle lineup page (user-provided)',is_active=true,sort_order=s.sort_order,updated_at=now() from lineup_import s where lower(trim(v.name))=lower(trim(s.name));
commit;
select vendor_type,count(*) vendor_count from public.vendors where source='Bite of Seattle lineup page (user-provided)' group by vendor_type order by vendor_type;
