insert into public.vendors(id,name,vendor_type,cuisines,food_types,menu_items,dietary_tags,description,review_count,review_snippets,line_status,instagram_url,source,is_active,sort_order,created_at,updated_at) select gen_random_uuid(),s.name,s.vendor_type,'{}','{}',s.menu_items,'{}',null,0,'{}',null,null,'Bite of Seattle lineup page (user-provided)',true,s.sort_order,now(),now() from lineup_import s where not exists(select 1 from public.vendors v where lower(trim(v.name))=lower(trim(s.name)));
